changeSet.sql:
DECLARE @enrollment1Id BIGINT;
DECLARE @lesson1Id BIGINT;
DECLARE @lesson2Id BIGINT;
DECLARE @lesson3Id BIGINT;

SELECT TOP 1 @enrollment1Id = e.id
FROM enrollment e
JOIN course c ON e.course_id = c.id
WHERE c.title = 'course_1';

SELECT @lesson1Id = id FROM lesson WHERE title = 'c1_m1_lesson_1';
SELECT @lesson2Id = id FROM lesson WHERE title = 'c1_m1_lesson_2';
SELECT @lesson3Id = id FROM lesson WHERE title = 'c1_m1_lesson_3';

INSERT INTO lesson_completion (enrollment_id, lesson_id, completed_at)
VALUES
(@enrollment1Id, @lesson1Id, DATEADD(day, -3, GETDATE())),
(@enrollment1Id, @lesson2Id, DATEADD(day, -2, GETDATE())),
(@enrollment1Id, @lesson3Id, DATEADD(day, -1, GETDATE()));
